if classification in (
    Classification.current_priority,
    Classification.current_packet_constraint,
) and expires_at is None:
    raise ValueError(
        f"classification={classification.value!r} requires expires_at"
    )

if classification == Classification.candidate_policy and policy_candidate_id is None:
    raise ValueError(
        "classification='candidate_policy' requires policy_candidate_id"
    )

if policy_candidate_id is not None:
    cand_org = _row_org_via_admin(
        "policy_candidates", "candidate_id", policy_candidate_id
    )
    if cand_org is not None and cand_org != org_id:
        raise OrgMismatchError(
            f"policy_candidate_id={policy_candidate_id} belongs to org "
            f"{cand_org}, not {org_id}"
        )
